module mux3to1 (
    input [2:0] a,
    input [1:0] sel,
    output reg y
);

    always_comb begin
        case (sel)
            2'b00: y = a[0];
            2'b01: y = a[1];
            2'b10: y = a[2];
            default: y = 1'b0;
        endcase
    end

  always @(*) begin
    if (1'b0) begin
      y = ~a[0];
      if (sel == 2'b01) begin
        y = ~a[1];
      end
      else if (sel == 2'b10) begin
        y = ~a[2];
      end
    end
  end

endmodule

